'use client';

/**
 * AluCalc OS — Visualizer Node
 * 
 * Renders 2D/3D visualizations driven by incoming data connections.
 * Supports:
 * - Reactive 3D models (Gears, Shafts)
 * - 2D Engineering Plots (Beams, Welds, Profiles)
 * - Technical Drawing Previews
 */

import React, { memo, useMemo } from 'react';
import { NodeProps, Handle, Position } from 'reactflow';
import { X, Maximize2, Settings, Eye, Send } from 'lucide-react';
import type { VisualizerNodeData } from '@/store/flowStore';
import { useFlowStore } from '@/store/flowStore';
import { useCadStore } from '@/cad/store/cadStore';

// Visualizers
import { ProfileVisualization } from '@/components/visualizers/ProfileVisualization';
import { GearVisualization } from '@/components/GearVisualization';
import WeldingVisualization, { WeldType } from '@/components/WeldingVisualization';

// ============================================
// Styles
// ============================================

const styles = {
    node: `
        min-w-[320px] bg-[#0f1419] 
        rounded-lg shadow-2xl border border-[#2a3a4a]
        overflow-hidden
    `,
    nodeSelected: `
        border-[#00e5ff] ring-2 ring-[#00e5ff]/30
    `,
    header: `
        flex items-center justify-between gap-2 px-3 py-2
        bg-gradient-to-r from-[#1a2332] to-[#0f1419]
        border-b border-[#2a3a4a] cursor-move
    `,
    headerTitle: `
        text-xs font-bold text-gray-400 uppercase tracking-wider
        flex items-center gap-2
    `,
    headerBtn: `
        p-1 rounded hover:bg-white/10 text-gray-500 hover:text-white
        transition-colors cursor-pointer
    `,
    body: `
        p-2 bg-[#0a0e14] relative min-h-[200px] flex items-center justify-center
    `,
    handle: `
        !w-3 !h-3 !bg-[#2a3a4a] !border-2 !border-[#00e5ff]
        hover:!bg-[#00e5ff] transition-colors
    `,
    handleLabel: `
        absolute text-[10px] text-gray-500 font-mono
        pointer-events-none whitespace-nowrap
    `,
};

// ============================================
// Main Component
// ============================================

const VisualizerNode: React.FC<NodeProps<VisualizerNodeData>> = ({
    id,
    data,
    selected
}) => {
    const { removeNode } = useFlowStore();
    const addEntity = useCadStore(state => state.addEntity);

    // ─────────────────────────────────────────
    // Helper Functions for CAD Export
    // ─────────────────────────────────────────

    const exportProfileToCad = (inputs: any) => {
        const type = Number(inputs?.profileType) || 1;
        const w = Number(inputs?.width) || 100;
        const h = Number(inputs?.height) || 50;
        const t = Number(inputs?.thickness) || 3;

        const layer = '0';
        const color = '#00e5ff';

        const outputDefaults = {
            layerId: layer,
            color: color,
            lineType: 'CONTINUOUS',
            lineWeight: 1,
            isSelected: false,
            isVisible: true,
        } as const;

        const addPoly = (pts: { x: number, y: number }[]) => {
            addEntity({
                id: crypto.randomUUID(),
                ...outputDefaults,
                geometry: {
                    type: 'POLYLINE',
                    vertices: pts,
                    closed: true
                }
            });
        };

        if (type === 1) { // Box
            addPoly([{ x: 0, y: 0 }, { x: w, y: 0 }, { x: w, y: h }, { x: 0, y: h }]); // Outer
            addPoly([{ x: t, y: t }, { x: w - t, y: t }, { x: w - t, y: h - t }, { x: t, y: h - t }]); // Inner
        } else if (type === 2) { // Tube
            addEntity({
                id: crypto.randomUUID(),
                ...outputDefaults,
                geometry: { type: 'CIRCLE', center: { x: w / 2, y: w / 2 }, radius: w / 2 }
            });
            addEntity({
                id: crypto.randomUUID(),
                ...outputDefaults,
                geometry: { type: 'CIRCLE', center: { x: w / 2, y: w / 2 }, radius: (w / 2) - t }
            });
        } else if (type === 3) { // L-Angle
            // L-shape with uniform thickness
            const pts = [
                { x: 0, y: 0 },
                { x: w, y: 0 },
                { x: w, y: t },
                { x: t, y: t },
                { x: t, y: h },
                { x: 0, y: h }
            ];
            addPoly(pts);
        } else if (type === 4) { // U-Channel
            // U-shape. Inputs: w (flange width), h (height), t (flange thick), tw (web thick)
            // Defaulting web thickness to flange thickness if not provided
            const tw = Number(inputs?.webThickness) || t;
            const pts = [
                { x: 0, y: 0 },
                { x: w, y: 0 },
                { x: w, y: t },
                { x: tw, y: t },
                { x: tw, y: h - t },
                { x: w, y: h - t },
                { x: w, y: h },
                { x: 0, y: h }
            ];
            addPoly(pts);
        } else if (type === 5) { // I-Beam
            // I-shape. Inputs: w (flange width), h (height), t (flange thick), tw (web thick)
            const tw = Number(inputs?.webThickness) || t;
            const flangeW = w;
            const webX = (w - tw) / 2;

            const pts = [
                { x: 0, y: 0 },
                { x: w, y: 0 },
                { x: w, y: t },
                { x: webX + tw, y: t },
                { x: webX + tw, y: h - t },
                { x: w, y: h - t },
                { x: w, y: h },
                { x: 0, y: h },
                { x: 0, y: h - t },
                { x: webX, y: h - t },
                { x: webX, y: t },
                { x: 0, y: t }
            ];
            addPoly(pts);
        }
        alert(`Exported Profile (Type ${type}) to CAD.`);
    };

    const exportGearToCad = (inputs: any) => {
        const gearModule = Number(inputs?.module) || 2;
        const teeth = Number(inputs?.gearTeeth) || 40;
        const x1 = Number(inputs?.x1) || 0;

        const pitchRadius = (gearModule * teeth) / 2;
        const addendum = gearModule * (1 + x1);
        const dedendum = gearModule * (1.25 - x1);
        const outsideRadius = pitchRadius + addendum;
        const rootRadius = pitchRadius - dedendum;

        const defaults = {
            layerId: '0',
            lineType: 'CONTINUOUS',
            lineWeight: 1,
            isSelected: false,
            isVisible: true
        } as const;

        addEntity({
            id: crypto.randomUUID(),
            color: '#00e5ff',
            geometry: { type: 'CIRCLE', center: { x: 0, y: 0 }, radius: pitchRadius },
            ...defaults
        });
        addEntity({
            id: crypto.randomUUID(),
            color: '#ffffff', // Tip
            geometry: { type: 'CIRCLE', center: { x: 0, y: 0 }, radius: outsideRadius },
            ...defaults
        });
        addEntity({
            id: crypto.randomUUID(),
            color: '#ff9800', // Root
            geometry: { type: 'CIRCLE', center: { x: 0, y: 0 }, radius: rootRadius },
            ...defaults
        });

        alert(`Exported Gear (M${gearModule}, Z${teeth}) to CAD.`);
    };

    const exportWeldingToCad = (inputs: any) => {
        const leg = Number(inputs?.legSize) || 5;

        const defaults = {
            layerId: '0',
            lineType: 'CONTINUOUS',
            lineWeight: 1,
            isSelected: false,
            isVisible: true
        } as const;

        addEntity({
            id: crypto.randomUUID(),
            color: '#ff00ff',
            geometry: {
                type: 'POLYLINE',
                vertices: [
                    { x: 0, y: 0 },
                    { x: leg, y: 0 },
                    { x: 0, y: leg },
                    { x: 0, y: 0 }
                ],
                closed: true
            },
            ...defaults
        });
        alert(`Exported Fillet Weld (a=${leg}) to CAD.`);
    };

    // ─────────────────────────────────────────
    // Handles & Operations
    // ─────────────────────────────────────────

    // Define input handles based on visualization type
    const handles = useMemo(() => {
        switch (data.vizType) {
            case 'gear':
                return [
                    { id: 'module', label: 'Module', top: 20 },
                    { id: 'pinionTeeth', label: 'Pinion Teeth', top: 40 },
                    { id: 'gearTeeth', label: 'Gear Teeth', top: 60 },
                    { id: 'pressureAngle', label: 'Pressure Angle', top: 80 },
                ];
            case 'welding':
                return [
                    { id: 'legSize', label: 'Leg Size (a)', top: 20 },
                    { id: 'thickness', label: 'Thickness (t)', top: 40 },
                ];
            default:
                return [];
        }
    }, [data.vizType]);

    // CAD Export Logic
    const handleExportToCAD = () => {
        try {
            switch (data.vizType) {
                case 'gear':
                    exportGearToCad(data.inputs);
                    break;
                case 'welding':
                    exportWeldingToCad(data.inputs);
                    break;
                case 'profile':
                case 'box-profile':
                    exportProfileToCad(data.inputs);
                    break;
                default:
                    alert('CAD export not implemented for this type yet.');
            }
        } catch (e) {
            console.error('CAD Export Failed', e);
            alert('Failed to export geometry to CAD.');
        }
    };

    const renderContent = () => {
        // Explicitly handle profile types
        if (data.vizType === 'profile' || data.vizType === 'box-profile' || data.vizType === 'details') {
            return (
                <ProfileVisualization
                    type={Number(data.inputs?.profileType) || 1 as any}
                    width={Number(data.inputs?.width) || 100}
                    height={Number(data.inputs?.height) || 50}
                    thickness={Number(data.inputs?.thickness) || 3}
                    webThickness={Number(data.inputs?.webThickness)}
                    className="w-full"
                />
            );
        }

        switch (data.vizType) {
            case 'gear':
                const pinion = {
                    module: Number(data.inputs?.module) || 2,
                    teeth: Number(data.inputs?.pinionTeeth) || 20,
                    pressureAngle: Number(data.inputs?.pressureAngle) || 20,
                    label: 'Driver'
                };
                const gear = {
                    module: Number(data.inputs?.module) || 2,
                    teeth: Number(data.inputs?.gearTeeth) || 40,
                    label: 'Driven'
                };
                return (
                    <GearVisualization
                        pinion={pinion}
                        gear={gear}
                        showAnnotations={true}
                        showMesh={true}
                        className="w-full"
                    />
                );

            case 'welding':
                const type: WeldType = (data.inputs?.type as WeldType) || 'fillet';
                const legSize = Number(data.inputs?.legSize) || 5;
                const thickness = Number(data.inputs?.thickness) || 10;

                return (
                    <WeldingVisualization
                        type={type}
                        legSize={legSize}
                        thickness={thickness}
                        className="w-full"
                    />
                );

            default:
                return (
                    <div className="text-gray-500 text-xs flex flex-col items-center gap-2">
                        <Eye size={24} />
                        <span>No visualization selected</span>
                        <div className="text-[10px] opacity-50">{data.vizType}</div>
                    </div>
                );
        }
    };

    return (
        <div className={`${styles.node} ${selected ? styles.nodeSelected : ''}`}>
            {/* Dynamic Input Handles */}
            {handles.map((h, i) => (
                <div key={h.id} style={{ position: 'absolute', left: 0, top: h.top + 40 }}>
                    <Handle
                        type="target"
                        position={Position.Left}
                        id={h.id}
                        className={styles.handle}
                    />
                    <span className={`${styles.handleLabel} left-4`}>
                        {h.label}
                    </span>
                </div>
            ))}

            {/* Header */}
            <div className={`${styles.header} draggable-handle`}>
                <div className={styles.headerTitle}>
                    <Eye size={14} className="text-amber-500" />
                    {data.title || 'Visualizer'}
                </div>
                <div className="flex items-center gap-1">
                    <button
                        className={styles.headerBtn}
                        onClick={handleExportToCAD}
                        title="Send to CAD"
                    >
                        <Send size={12} className="-rotate-45" />
                    </button>
                    <button className={styles.headerBtn}>
                        <Maximize2 size={12} />
                    </button>
                    <button className={styles.headerBtn}>
                        <Settings size={12} />
                    </button>
                    <button
                        className={styles.headerBtn}
                        onClick={(e) => {
                            e.stopPropagation();
                            removeNode(id);
                        }}
                    >
                        <X size={12} />
                    </button>
                </div>
            </div>

            {/* Body */}
            <div className={styles.body}>
                {renderContent()}
            </div>
        </div>
    );
};

export default memo(VisualizerNode);
